/**
 * Parse JUnit XML (Maestro output) into a flat array of test results.
 * Uses regex-based parsing — no external XML dependency needed.
 * Handles the subset of JUnit XML that Maestro produces.
 */

export function parseMaestro(xml) {
  const tests = [];
  const testcaseRegex = /<testcase\s+([^>]*?)(?:\/>|>([\s\S]*?)<\/testcase>)/g;
  let match;

  while ((match = testcaseRegex.exec(xml)) !== null) {
    const attrs = parseAttributes(match[1]);
    const body = match[2] || '';
    tests.push(parseTestCase(attrs, body));
  }

  return tests;
}

function parseTestCase(attrs, body) {
  const name = attrs.name || 'unknown';
  const durationSec = parseFloat(attrs.time || '0');
  const duration_ms = Math.round(durationSec * 1000);

  const hasSkipped = /<skipped\s*\/?>/.test(body);
  const failureMatch = body.match(/<failure\s+([^>]*)>/);
  const errorMatch = body.match(/<error\s+([^>]*)>/);

  if (hasSkipped) {
    return { name, status: 'skipped', duration_ms: 0, error: null };
  }

  const faultMatch = failureMatch || errorMatch;
  if (faultMatch) {
    const faultAttrs = parseAttributes(faultMatch[1]);
    return {
      name,
      status: 'failed',
      duration_ms,
      error: faultAttrs.message || 'Unknown error',
    };
  }

  return { name, status: 'passed', duration_ms, error: null };
}

function parseAttributes(attrString) {
  const attrs = {};
  const attrRegex = /(\w+)="([^"]*)"/g;
  let match;
  while ((match = attrRegex.exec(attrString)) !== null) {
    attrs[match[1]] = match[2];
  }
  return attrs;
}
